#include<bits/stdc++.h>
using namespace std;
int n,m,cx,cy;
long long dp[1010][1010];
bool youma(int x,int y){
    int dx[8]={-1,-2,-2,-1,1,2,2,1},
        dy[8]={-2,-1,1,2,2,1,-1,-2};
    for(int i=0;i<8;i++){
    	
        if(x==cx-dx[i]&&y==cy-dy[i]){
            return false;
        }
    }
    if(x==cx&&y==cy)return false;
    return true;
}
void draw(){
	for(int i=0;i<=n;i++){
    	for(int j=0;j<=m;j++){
    		cout<<dp[i][j]<<" ";
		}
		cout<<endl;
	}
}
int main()
{
    cin>>n>>m>>cx>>cy;
    if(youma(0,0))dp[0][0]=1;
 //   cout<<dp[0][0]<<endl;
    for(int i=1;i<=n;i++){
    	if(youma(i,0))dp[i][0]=dp[i-1][0];	
	}
  //  draw();
   // cout<<endl;
    for(int i=1;i<=m;i++)if(youma(0,i))dp[0][i]=dp[0][i-1];
	//draw();
    for(int i=1;i<=n;i++){
    	for(int j=1;j<=m;j++){
    		if(youma(i,j))dp[i][j]=dp[i-1][j]+dp[i][j-1];
		}
	}
	cout<<dp[n][m];
}
